user_stories:
{
  "user_stories": [
    {
      "id": 1,
      "role": "Player",
      "goal": "Submit game feedback with contact details",
      "benefit": "I can be followed up and know my feedback was received",
      "acceptance_criteria": [
        "Form supports category, description, severity, optional attachment, consent, and contact fields",
        "After submit, user sees confirmation with a reference ID"
      ]
    },
    {
      "id": 2,
      "role": "Player",
      "goal": "Understand privacy and consent for sharing contact info",
      "benefit": "I feel safe providing details",
      "acceptance_criteria": [
        "Consent checkbox is required when contact details are provided",
        "Privacy/retention notice is visible from the form"
      ]
    },
    {
      "id": 3,
      "role": "Product Manager",
      "goal": "Triage incoming feedback in a dashboard",
      "benefit": "I can prioritize and drive items to resolution",
      "acceptance_criteria": [
        "Dashboard provides search plus filter/sort by status, severity, tag, and assignee",
        "PM can update status, add tags, assign owner, and add internal notes"
      ]
    },
    {
      "id": 4,
      "role": "Customer Support Agent",
      "goal": "Follow up with players and log outcomes",
      "benefit": "I can resolve issues efficiently with history tracked",
      "acceptance_criteria": [
        "Feedback detail shows contact info and full activity history",
        "Agent can send via template/link-out and record notes and follow-up reminders"
      ]
    },
    {
      "id": 5,
      "role": "Admin",
      "goal": "Protect feedback data with secure access and controls",
      "benefit": "Sensitive data is handled safely and compliantly",
      "acceptance_criteria": [
        "Internal users authenticate via SSO and access is role-based",
        "Data is encrypted in transit/at rest and changes are captured in an audit trail"
      ]
    }
  ]
}
